import {{ Injectable }} from '@nestjs/common';
import {{ ShippingService }} from './models/shipping.model';
import {{ ShippingServiceRepository }} from './repositories/shipping.repository';

@Injectable()
export class ShippingServiceService {{
  constructor(
    private readonly repository: ShippingServiceRepository,
  ) {{}}

  async findAll(): Promise<ShippingService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ShippingService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ShippingService>): Promise<ShippingService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ShippingService>): Promise<ShippingService> {{
    return this.repository.update(id, data);
  }}
}}
